# DE 1751.  Wunstorf - Gümmerwald
#
let wl = path("d3.de.1750");

with detail = 4,
     railway = :first :double :cat:ac15 :nopax
{
    with link = "line.de.1751" {
        track(:ror,
                wl[:wun + 1099m, :wun + 1100m] << 2mo
            ..  wl[:gum.yw - 0.1dl, :gum.yw] << 3mo
        );
        track(:ror:lor :casing,
                wl[:gum.yw - 0.1dl, :gum.yw] << 3mo
            ..  wl[:gum.xw - 0.1dl, :gum.xw] >> 5mo
        );
        track(:ror:lor,
                wl[:gum.xw - 0.1dl, :gum.xw] >> 5mo
            ..  wl[:gum - 3.1dl, :gum - 3dl] >> 3mo
        );
    }
}

